import os
import json
from openai import OpenAI
from dotenv import load_dotenv

# 加载 .env 里的环境变量
load_dotenv()

# 初始化 OpenAI 客户端
# 它会自动去读系统环境变量里的 OPENAI_API_KEY 和 OPENAI_BASE_URL
client = OpenAI()

def analyze_food_image_with_ai(image_base64: str) -> dict:
    """
    核心 AI 视觉分析服务：
    接收一张食物照片的 Base64 编码，让大模型分析并返回结构化的 JSON 数据。
    """
    
    # === 核心提示词工程 (Prompt Engineering) ===
    # 这是让大模型“听话”的关键，强制要求它以 JSON 格式输出，且数值范围固定
    system_prompt = """
    你是一位顶级的公共营养师。你的任务是分析用户上传的食物照片。
    你需要识别出食物的名称，并根据其成分估算它对人体（或宠物）几项核心健康值（HP）的影响。
    
    规则：
    1. 返回的结果必须是一个合法的 JSON 对象，不要包含任何 markdown 代码块标记，不要多余的废话。
    2. 数值规则：
       - hp_changes 里的所有值必须是整数，范围在 -30 到 +30 之间。
       - 垃圾食品（如油炸、高糖）应大幅扣除微量元素（iron, calcium, iodine, vit_c 为负数），并增加肥胖值（fat 为正数，比如 20）。
       - 健康食品应增加对应的微量元素（如吃蔬菜加 vit_c），并降低肥胖值（fat 为负数，比如 -5）。
       
    输出的 JSON 格式必须完全如下：
    {
      "food": "你识别出的食物名称",
      "is_healthy": true 或 false,
      "hp_changes": {
        "fat": 15,
        "iron": -5,
        "calcium": 2,
        "iodine": 0,
        "vit_c": -10
      },
      "reasoning": "一两句话解释你的判断逻辑"
    }
    """

    try:
        # 从环境变量获取模型名，如果没有配置，默认用 gpt-4o 
        # (因为部分中转平台不支持 gpt-4o-mini，但几乎所有平台都支持 gpt-4o)
        model_name = os.getenv("LLM_MODEL_NAME", "gpt-4o")
        print(f"正在向大模型 ({model_name}) 发送图片进行视觉分析...")
        response = client.chat.completions.create(
            model=model_name,
            messages=[
                {
                    "role": "system",
                    "content": system_prompt
                },
                {
                    "role": "user",
                    "content": [
                        {"type": "text", "text": "请分析这张食物照片的营养价值。"},
                        {
                            "type": "image_url",
                            "image_url": {
                                # 注意：如果是真实上传，这里需要拼接 "data:image/jpeg;base64," + image_base64
                                "url": f"data:image/jpeg;base64,{image_base64}",
                            },
                        },
                    ],
                }
            ],
            max_tokens=300,
            temperature=0.3 # 调低温度，让大模型的输出更确定、不乱发散
        )
        
        # 提取返回的 JSON 字符串
        raw_json_str = response.choices[0].message.content
        
        # 清理可能被大模型加上的 markdown 格式 (如 ```json ... ```)
        clean_json_str = raw_json_str.strip().strip('`').removeprefix('json')
        
        # 解析为 Python 字典
        result = json.loads(clean_json_str)
        return result
        
    except Exception as e:
        print(f"AI 分析失败: {e}")
        # 如果 AI 挂了或者超时了，返回一个保底的兜底数据，保证系统不崩溃
        return {
            "food": "未知食物",
            "is_healthy": True,
            "hp_changes": {"fat": 0, "iron": 0, "calcium": 0, "iodine": 0, "vit_c": 0},
            "reasoning": "AI 分析失败，这是保底的默认数据。"
        }

def analyze_craving_with_ai(craving_food: str) -> dict:
    """
    纯文本 AI 分析服务：
    根据用户想吃的食物，推断身体缺乏的营养素。
    """
    system_prompt = """
    你是一位顶级的营养学专家。用户会告诉你他们现在非常渴望（Craving）吃某种食物。
    请你根据营养学常识，推断出他们身体最可能缺乏哪一种核心营养素（仅限：iron, calcium, iodine, vit_c）。
    如果想吃高热量/油炸，通常选 calcium；想吃甜/冰，选 iron；想吃咸，选 iodine；想吃酸/辣/疲劳，选 vit_c。
    
    输出必须是合法的 JSON 格式，如下：
    {
      "lacking_element": "iron",  // 必须是 iron, calcium, iodine, vit_c 中的一个
      "analysis_message": "你现在想吃这个，可能是因为..." // 一段有教育意义、友好的营养学解释（50字左右）
    }
    """
    try:
        model_name = os.getenv("LLM_MODEL_NAME", "gpt-4o")
        response = client.chat.completions.create(
            model=model_name,
            messages=[
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": f"我好想吃：{craving_food}"}
            ],
            max_tokens=200,
            temperature=0.5
        )
        
        raw_json_str = response.choices[0].message.content
        clean_json_str = raw_json_str.strip().strip('`').removeprefix('json')
        return json.loads(clean_json_str)
        
    except Exception as e:
        print(f"AI 食欲分析失败: {e}")
        return {
            "lacking_element": "vit_c",
            "analysis_message": "系统未能解析你的食欲，但补充维C总是没错的！"
        }

# ==========================================
# 测试代码 (只有当你直接运行这个文件时才会执行)
# ==========================================
if __name__ == "__main__":
    # 这里我们不用真实的 base64 测（太长了），你可以找一张网上的炸鸡图片转成 base64 贴进来测
    test_base64 = "" 
    print("发送测试请求 (使用假图片)...")
    res = analyze_food_image_with_ai(test_base64)
    print("====== AI 返回的分析结果 ======")
    print(json.dumps(res, indent=2, ensure_ascii=False))
